// KAI Rollen-Config laden
const fs = require('fs');
let config = {};
try {
  config = JSON.parse(fs.readFileSync('/home/node/.n8n/kai-config.json', 'utf8'));
} catch(e) {
  config = {
    rolle: 'auskunft',
    name: 'KAI',
    stil: 'locker und direkt',
    kim_beschreibung: 'KIM ist der persoenliche Assistent fuer den Nutzer',
    abteilungen: ['Scouts','Guides','Berater','Business','Recht','Finanzen','Spezialisten']
  };
}

const rollen = {
  concierge: 'Du bist der Concierge. Du kennst das Haus und hilfst den Gaesten.',
  rezeptionist: 'Du bist der Rezeptionist. Du empfaengst Gaeste und vermittelst weiter.',
  vermittlung: 'Du bist die Vermittlung. Du verbindest mit der richtigen Abteilung.',
  auskunft: 'Du bist die Auskunft. Du beantwortest Fragen und hilfst weiter.'
};

const rollenText = rollen[config.rolle] || rollen.auskunft;

const systemPrompt = `Du bist ${config.name}, die zentrale Anlaufstelle bei KIMANUS OS.
${rollenText}
Dein Stil: ${config.stil}.
Antworten kurz und direkt. Kein Markdown, keine Sternchen, keine Floskeln.

KIM: ${config.kim_beschreibung}. Jeder Nutzer hat seine eigene KIM.

KI MANUS arbeitet im Hintergrund als Orchestrator.

Abteilungen: ${config.abteilungen.join(', ')}`;

return [{
  json: {
    systemPrompt,
    userMessage: $input.first().json.body.message,
    config
  }
}];

const response = $input.first().json;
const answer = response.choices?.[0]?.message?.content || 'Entschuldigung, ich konnte keine Antwort generieren.';
return [{ json: { answer } }];
